    let s = String::from("hola");

    // Préstamo inmutable → puedes tener MUCHOS
    let r1 = &s;
    let r2 = &s;
    println!("{} {}", r1, r2); // ✅

    // Préstamo mutable → solo UNO a la vez
    let mut s2 = String::from("mundo");
    let r3 = &mut s2;
